body:
Found inspecting/linting Verilog emitted in our lit tests.

Test added in #2359 is missing some `CHECK:` markers which let this slip--but the issue is that it looks like we're not correctly/fully/consistently renaming fields, consider this input (extracted from `hw-dialect.mlir`):

```mlir
// RUN: circt-opt %s --test-apply-lowering-options='options=emittedLineLength=100,emitBindComments' -export-verilog -verify-diagnostics -o %t.mlir | FileCheck %s

// Rename field names
// CHECK-LABEL: renameKeyword(
// CHECK-NEXT:  input  struct packed {logic repeat_0; logic repeat_0_0; } a,
// CHECK-NEXT:  output struct packed {logic repeat_0; logic repeat_0_0; } r1
// CHECK-NEXT:  );
hw.module @renameKeyword(in %a: !hw.struct<repeat: i1, repeat_0: i1>, out r1: !hw.struct<repeat: i1, repeat_0: i1>){
  hw.output %a : !hw.struct<repeat: i1, repeat_0: i1>
}

// CHECK-LABEL: useRenamedStruct(
// CHECK-NEXT:  inout  struct packed {logic repeat_0; logic repeat_0_0; } a,
// CHECK-NEXT:  output                                                    r1,
// CHECK-NEXT:                                                            r2,
// CHECK-NEXT:  output struct packed {logic repeat_0; logic repeat_0_0; } r3, 
// CHECK-NEXT:                                                            r4
// CHECK-NEXT:  );
hw.module @useRenamedStruct(inout %a: !hw.struct<repeat: i1, repeat_0: i1>, out r1: i1, out r2: i1, out r3: !hw.struct<repeat: i1, repeat_0: i1>, out r4: !hw.struct<repeat: i1, repeat_0: i1>) {
  %read = sv.read_inout %a : !hw.inout<struct<repeat: i1, repeat_0: i1>>

  %i0 = hw.instance "inst1" @renameKeyword(a: %read: !hw.struct<repeat: i1, repeat_0: i1>) -> (r1: !hw.struct<repeat: i1, repeat_0: i1>)
  // CHECK:      renameKeyword inst1 (
  // CHECK-NEXT:   .a  (a),
  // CHECK-NEXT:   .r1 (r4)
  // CHECK-NEXT: )

  %0 = sv.struct_field_inout %a["repeat"] : !hw.inout<struct<repeat: i1, repeat_0: i1>>
  %1 = sv.read_inout %0 : !hw.inout<i1>
  // CHECK: assign r1 = a.repeat_0;
  %2 = hw.struct_extract %read["repeat_0"] : !hw.struct<repeat: i1, repeat_0: i1>
  // CHECK: assign r2 = a.repeat_0_0;
  %true = hw.constant true
  %3 = hw.struct_inject %read["repeat_0"], %true : !hw.struct<repeat: i1, repeat_0: i1>
  // CHECK: assign r3 = '{repeat_0: a.repeat_0, repeat_0_0: (1'h1)};
  hw.output %1, %2, %3, %i0 : i1, i1, !hw.struct<repeat: i1, repeat_0: i1>, !hw.struct<repeat: i1, repeat_0: i1>
}
```

We emit the following:
```systemverilog
// Generated by CIRCT firtool-1.57.1-5-g63feeb386
module renameKeyword(	// rename-test.mlir:8:1
  input  struct packed {logic repeat_0; logic repeat_0_0; } a,	// rename-test.mlir:8:29
  output struct packed {logic repeat_0; logic repeat_0_0; } r1	// rename-test.mlir:8:75
);

  assign r1 = a;	// rename-test.mlir:9:3
endmodule

module useRenamedStruct(	// rename-test.mlir:19:1
  inout  struct packed {logic repeat_0; logic repeat_0_0; } a,	// rename-test.mlir:19:35
  output                                                    r1,	// rename-test.mlir:19:81
                                                            r2,	// rename-test.mlir:19:93
  output struct packed {logic repeat_0; logic repeat_0_0; } r3,	// rename-test.mlir:19:105
                                                            r4	// rename-test.mlir:19:151
);

  renameKeyword inst1 (	// rename-test.mlir:22:9
    .a  (a),	// rename-test.mlir:20:11
    .r1 (r4)
  );
  assign r1 = a.repeat_0;	// rename-test.mlir:28:8, :29:8, :36:3
  assign r2 = a.repeat_0_0;	// rename-test.mlir:20:11, :31:8, :36:3
  assign r3 = '{repeat_0: a.repeat, repeat_0_0: (1'h1)};	// rename-test.mlir:20:11, :33:11, :34:8, :36:3
endmodule
```

In particular the problem is `repeat_0: a.repeat` -- this should be `a.repeat_0_0` I think but definitely not `repeat` which is a keyword and not a field in `a`.

Verilator lint output, FWIW:

```
%Error: /proc/self/fd/11:24:29: syntax error, unexpected repeat
   24 |   assign r3 = '{repeat_0: a.repeat, repeat_0_0: (1'h1)};  
      |                             ^~~~~~
%Error: Exiting due to 1 error(s)
```
